import{_ as e,c as a,o as t,a2 as i}from"./chunks/framework.BJ4bFU3Q.js";const r="/assets/results.BiJ5Fkea.png",f=JSON.parse('{"title":"CS311 Artificial Intelligence","description":"","frontmatter":{},"headers":[],"relativePath":"articles/Project_Hubs/CS311.md","filePath":"articles/Project_Hubs/CS311.md"}'),o={name:"articles/Project_Hubs/CS311.md"},n=i('<h1 id="cs311-artificial-intelligence" tabindex="-1">CS311 Artificial Intelligence <a class="header-anchor" href="#cs311-artificial-intelligence" aria-label="Permalink to &quot;CS311 Artificial Intelligence&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>Contributors: Yicheng Xiao</p></div><p>There are in total 3 projects in this course.</p><ul><li><strong>Project 1: Search Algorithms</strong><ul><li>Reversed Reversi</li></ul></li><li><strong>Project 2: Constraint Satisfaction Problems</strong><ul><li>CARP Problems</li></ul></li><li><strong>Project 3: Machine Learning</strong></li></ul><h2 id="project-1-search-algorithms" tabindex="-1">Project 1: Search Algorithms <a class="header-anchor" href="#project-1-search-algorithms" aria-label="Permalink to &quot;Project 1: Search Algorithms&quot;">​</a></h2><p>Unfortunately, my Reversed Reversi did not exhibit very good performance as I was preparing for the ASC24 during the time. I have implemented basic histogram minimax search and alpha-beta pruning in the project.</p><h2 id="project-2-constraint-satisfaction-problems" tabindex="-1">Project 2: Constraint Satisfaction Problems <a class="header-anchor" href="#project-2-constraint-satisfaction-problems" aria-label="Permalink to &quot;Project 2: Constraint Satisfaction Problems&quot;">​</a></h2><p>In this project, I have implemented the Genetic Algortihm and use Path Scanning as initialization for the population in the CARP problems. The Genetic Algorithm is used to solve the CARP problems and the results are shown below: <img src="'+r+'" alt="Result"></p><h2 id="project-3-machine-learning" tabindex="-1">Project 3: Machine Learning <a class="header-anchor" href="#project-3-machine-learning" aria-label="Permalink to &quot;Project 3: Machine Learning&quot;">​</a></h2><p>In this project, I have tested the following models on the dataset of the project:</p><ul><li>Decision Tree</li><li>Naive Bayes</li><li>Nearest Neighbors</li><li>Ensemble Models</li><li>Support Vector Machine</li><li>Neuron Networks The best performance is achieved by Random Forest with an accuracy of 0.86.</li></ul><h2 id="final-exam" tabindex="-1">Final Exam <a class="header-anchor" href="#final-exam" aria-label="Permalink to &quot;Final Exam&quot;">​</a></h2><p>You can refer to one of my friend Mengxuan Wu to get a memorized version of our final exam. <a href="https://github.com/Cypher-Bruce/SUSTech-CS-Course/blob/main/CS311%20Artificial%20Intelligence%20(H)/Final%20Exam/Exam%20Paper.pdf" target="_blank" rel="noreferrer">Final Exam</a></p><p>The github repository: <a href="https://github.com/Jaredanwolfgang/CS311_Project3_Machine_Learning" target="_blank" rel="noreferrer">Machine Learning</a></p>',14),l=[n];function s(c,h,m,p,d,u){return t(),a("div",null,l)}const b=e(o,[["render",s]]);export{f as __pageData,b as default};
